def led_loop(api, pixels, memory, current_time, is_new_frame) -> None:
    # 1. Setup variables
    if "flash_toggle" not in memory:
        memory["flash_toggle"] = False
        memory["last_flash"] = current_time
        memory["state"] = "IDLE"
        memory["elapsed"] = 0.0

    if current_time - memory["last_flash"] > 0.5:
        memory["flash_toggle"] = not memory["flash_toggle"]
        memory["last_flash"] = current_time

    # 2. Read the Tags from the Tagger
    if is_new_frame and api:
        global_tags = api.get_value("Hailo", "global_tags", [])
        for tag in global_tags:
            if tag.startswith("STATE:"):
                memory["state"] = tag.split(":")[1]
            elif tag.startswith("TIME:"):
                try:
                    memory["elapsed"] = float(tag.split(":")[1])
                except ValueError:
                    pass

    state = memory["state"]
    elapsed = memory["elapsed"]
    num_pixels = len(pixels) # Dynamically checks if you have 12, 16, or 24 LEDs!

    # 3. Erase the ring every frame before drawing the new clock
    pixels.fill((0, 0, 0))

    # 4. Draw the Clock Output
    if state == "WORK_OK":
        # Calculate how many LEDs to light up (0 to 15 seconds)
        fill_count = int((elapsed / 15.0) * num_pixels)
        for i in range(min(fill_count, num_pixels)):
            pixels[i] = (50, 50, 50) # Dim White

    elif state == "WORK_VIOLATION":
        if memory["flash_toggle"]: pixels.fill((255, 0, 0)) # Flash Red

    elif state == "WORK_OVER":
        if memory["flash_toggle"]: pixels.fill((0, 255, 0)) # Flash Green (Time to leave!)

    elif state == "BREAK_OK":
        # Calculate how many LEDs to light up (0 to 5 seconds)
        fill_count = int((elapsed / 5.0) * num_pixels)
        for i in range(min(fill_count, num_pixels)):
            pixels[i] = (0, 255, 0) # Green

    elif state == "BREAK_VIOLATION":
        if memory["flash_toggle"]: pixels.fill((255, 0, 0)) # Flash Red (Get away from desk!)

    elif state == "BREAK_OVER":
        # Flash Green (Time to work!)
        if memory["flash_toggle"]: pixels.fill((0, 255, 0)) 

    # Push to hardware
    pixels.show()

def oled_draw(api, draw, memory, current_time, is_new_frame):
    # 1. Initialize Memory
    if "state" not in memory:
        memory["state"] = "IDLE"
        memory["elapsed"] = "0.0"

    # 2. Extract Data from the Tagger
    if is_new_frame and api:
        tags = api.get_value("Hailo", "global_tags", [])
        for tag in tags:
            if tag.startswith("STATE:"):
                memory["state"] = tag.split(":")[1]
            elif tag.startswith("TIME:"):
                memory["elapsed"] = tag.split(":")[1]

    state = memory["state"]
    elapsed = memory["elapsed"]

    # 3. Map States to Text
    if state == "WORK_OK":
        msg1, msg2 = "FOCUS MODE", f"{elapsed}s / 15s"
    elif state == "WORK_VIOLATION":
        msg1, msg2 = "WHERE DID", "YOU GO?"
    elif state == "WORK_OVER":
        msg1, msg2 = "WORK DONE!", "Take a break."
    elif state == "BREAK_OK":
        msg1, msg2 = "RELAXING...", f"{elapsed}s / 5s"
    elif state == "BREAK_VIOLATION":
        msg1, msg2 = "STEP AWAY!", "Rest your eyes."
    elif state == "BREAK_OVER":
        msg1, msg2 = "BREAK OVER", "Time to work."
    else:
        msg1, msg2 = "WAITING FOR", "CAMERA..."

    # 4. Draw to the OLED (X, Y coords)
    draw.text((10, 15), msg1, fill=1)
    draw.text((10, 35), msg2, fill=1)
